import { Text } from '@react-email/components';
import type { ReactNode } from 'react';
import { getActiveBeaconPalette, getActiveBeaconTokens } from './token-context';

export interface EmailBodyTextProps {
  children: ReactNode;
  muted?: boolean;
  /** Tighter bottom margin for stacked list items. */
  compact?: boolean;
}

/**
 * Body copy with Beacon line-height and spacing.
 */
export function EmailBodyText({ children, muted = false, compact = false }: EmailBodyTextProps) {
  const tokens = getActiveBeaconTokens();
  const palette = getActiveBeaconPalette();

  return (
    <Text
      className={muted ? 'email-muted' : 'email-fg'}
      style={{
        color: muted ? palette.muted : palette.body,
        fontFamily: tokens.fontFamily.body,
        fontSize: tokens.fontSize.base,
        lineHeight: '22px',
        margin: compact ? '0 0 6px' : '0 0 12px',
        textAlign: 'left',
      }}
    >
      {children}
    </Text>
  );
}

import { Button as EmailButton } from '@react-email/components';
import type { ReactNode } from 'react';
import { getActiveBeaconTokens } from './token-context';

export interface EmailButtonProps {
  href: string;
  children: ReactNode;
  fullWidth?: boolean;
}

export function EmailButtonLink({ href, children, fullWidth = false }: EmailButtonProps) {
  const t = getActiveBeaconTokens();

  return (
    <EmailButton
      href={href}
      style={{
        backgroundColor: t.colors.primary,
        borderRadius: 7,
        color: t.colors.primaryForeground,
        display: fullWidth ? 'block' : 'inline-block',
        fontFamily: t.fontFamily.body,
        fontSize: t.fontSize.base,
        fontWeight: 500,
        margin: fullWidth ? '0 auto' : undefined,
        padding: '12px 26px',
        textAlign: 'center',
        textDecoration: 'none',
      }}
    >
      {children}
    </EmailButton>
  );
}

export function EmailButtonOutline({ href, children }: EmailButtonProps) {
  const t = getActiveBeaconTokens();

  return (
    <EmailButton
      href={href}
      style={{
        backgroundColor: 'transparent',
        border: `1px solid ${t.colors.border}`,
        borderRadius: 7,
        color: t.colors.foreground,
        display: 'inline-block',
        fontFamily: t.fontFamily.body,
        fontSize: t.fontSize.sm,
        fontWeight: 500,
        padding: `${t.spacing.sm} ${t.spacing.lg}`,
        textDecoration: 'none',
      }}
    >
      {children}
    </EmailButton>
  );
}

import { Section, Text } from '@react-email/components';
import type { ReactNode } from 'react';
import { getActiveBeaconPalette, getActiveBeaconTokens } from './token-context';

export interface EmailCalloutProps {
  children: ReactNode;
  title?: string;
}

/**
 * Forest stamp note block — title band on top, body below.
 */
export function EmailCallout({ children, title }: EmailCalloutProps) {
  const palette = getActiveBeaconPalette();
  const tokens = getActiveBeaconTokens();

  return (
    <Section
      style={{
        border: `1px solid ${palette.surfaceTint}`,
        borderRadius: 8,
        margin: '16px 0',
        overflow: 'hidden',
      }}
    >
      {title ? (
        <Section style={{ backgroundColor: palette.forest, padding: '10px 18px' }}>
          <Text
            style={{
              color: palette.forestMuted,
              fontFamily: palette.fontMono,
              fontSize: 10,
              margin: '0 0 4px',
              textAlign: 'left',
            }}
          >
            Note
          </Text>
          <Text
            style={{
              color: palette.forestText,
              fontFamily: tokens.fontFamily.body,
              fontSize: 13,
              fontWeight: 500,
              margin: 0,
              textAlign: 'left',
            }}
          >
            {title}
          </Text>
        </Section>
      ) : null}
      <Section
        style={{
          backgroundColor: palette.surface,
          padding: '14px 18px',
        }}
      >
        <Text
          style={{
            color: palette.body,
            fontFamily: tokens.fontFamily.body,
            fontSize: tokens.fontSize.sm,
            lineHeight: '20px',
            margin: 0,
            textAlign: 'left',
          }}
        >
          {children}
        </Text>
      </Section>
    </Section>
  );
}

import { Section, Text } from '@react-email/components';
import { isPresent } from './present';
import { getActiveBeaconTokens } from './token-context';

export function EmailCodeDisplay({
  code,
  expiresIn,
}: {
  code?: string;
  expiresIn?: string;
}) {
  const tokens = getActiveBeaconTokens();

  if (!isPresent(code)) return null;

  return (
    <Section style={{ margin: `${tokens.spacing.lg} 0` }}>
      <Text
        style={{
          color: tokens.colors.mutedForeground,
          fontSize: tokens.fontSize.sm,
          margin: `0 0 ${tokens.spacing.sm}`,
        }}
      >
        Your code
      </Text>
      <Text
        style={{
          backgroundColor: tokens.colors.muted,
          border: `1px solid ${tokens.colors.border}`,
          color: tokens.colors.foreground,
          display: 'inline-block',
          fontFamily: tokens.fontFamily.mono,
          fontSize: tokens.fontSize['2xl'],
          fontWeight: 600,
          lineHeight: '36px',
          margin: `0 0 ${tokens.spacing.sm}`,
          padding: `${tokens.spacing.sm} ${tokens.spacing.md}`,
        }}
      >
        {code}
      </Text>
      {isPresent(expiresIn) ? (
        <Text
          style={{
            color: tokens.colors.mutedForeground,
            fontSize: tokens.fontSize.sm,
            lineHeight: '22px',
            margin: 0,
          }}
        >
          Expires in {expiresIn}
        </Text>
      ) : null}
    </Section>
  );
}

import { Section, Text } from '@react-email/components';
import { EmailButtonLink, EmailButtonOutline } from './button';
import { getActiveBeaconTokens } from './token-context';

export interface EmailCtaSectionProps {
  href: string;
  label: string;
  caption?: string;
  secondaryHref?: string;
  secondaryLabel?: string;
}

/**
 * Centered CTA block with optional caption and secondary action.
 */
export function EmailCtaSection({
  href,
  label,
  caption,
  secondaryHref,
  secondaryLabel,
}: EmailCtaSectionProps) {
  const tokens = getActiveBeaconTokens();

  return (
    <Section style={{ margin: '20px 0 16px', textAlign: 'center' }}>
      <EmailButtonLink href={href}>{label}</EmailButtonLink>
      {secondaryHref && secondaryLabel ? (
        <Section style={{ marginTop: tokens.spacing.sm }}>
          <EmailButtonOutline href={secondaryHref}>{secondaryLabel}</EmailButtonOutline>
        </Section>
      ) : null}
      {caption ? (
        <Text
          className="email-muted"
          style={{
            color: tokens.colors.mutedForeground,
            fontSize: tokens.fontSize.xs,
            lineHeight: '18px',
            fontFamily: tokens.fontFamily.body,
            margin: '8px 0 0',
          }}
        >
          {caption}
        </Text>
      ) : null}
    </Section>
  );
}

import { Hr, Section, Text } from '@react-email/components';
import { getActiveBeaconTokens } from './token-context';

export interface EmailDividerProps {
  label?: string;
}

/**
 * Horizontal divider with optional centered label.
 */
export function EmailDivider({ label }: EmailDividerProps) {
  const tokens = getActiveBeaconTokens();

  if (!label) {
    return (
      <Hr
        className="email-border"
        style={{
          borderColor: tokens.colors.border,
          borderTop: `1px solid ${tokens.colors.border}`,
          margin: '16px 0',
        }}
      />
    );
  }

  return (
    <Section style={{ margin: '16px 0' }}>
      <table cellPadding={0} cellSpacing={0} style={{ width: '100%' }}>
        <tbody>
          <tr>
            <td style={{ borderTop: `1px solid ${tokens.colors.border}`, width: '42%' }} />
            <td style={{ padding: `0 ${tokens.spacing.sm}`, textAlign: 'center', width: '16%' }}>
              <Text
                className="email-muted"
                style={{
                  color: tokens.colors.mutedForeground,
                  fontSize: tokens.fontSize.xs,
                  margin: 0,
                }}
              >
                {label}
              </Text>
            </td>
            <td style={{ borderTop: `1px solid ${tokens.colors.border}`, width: '42%' }} />
          </tr>
        </tbody>
      </table>
    </Section>
  );
}

/**
 * Layout / shell props — header, footer, logo, legal.
 * Configure once in themes/beacon/brand.config.ts (not per template).
 */
export interface EmailBrandProps {
  appName: string;
  logoUrl?: string;
  logoAlt?: string;
  websiteUrl?: string;
  unsubscribeUrl?: string;
  termsUrl?: string;
  privacyUrl?: string;
  preferencesUrl?: string;
  legalName?: string;
  companyAddress?: string;
  supportUrl?: string;
  copyrightYear?: number;
}

export function withEmailBrandDefaults(brand: EmailBrandProps): EmailBrandProps {
  return {
    ...brand,
    legalName: brand.legalName ?? brand.appName,
    preferencesUrl: brand.preferencesUrl ?? brand.unsubscribeUrl,
  };
}

import { Text } from '@react-email/components';
import { getActiveBeaconPalette } from './token-context';

export interface EmailEyebrowProps {
  children: string;
}

/** Left-aligned section label above headings. */
export function EmailEyebrow({ children }: EmailEyebrowProps) {
  const palette = getActiveBeaconPalette();

  return (
    <Text
      style={{
        color: palette.forest,
        fontFamily: palette.fontMono,
        fontSize: 11,
        fontWeight: 500,
        margin: '0 0 6px',
        textAlign: 'left',
      }}
    >
      {children}
    </Text>
  );
}

import { Link, Section, Text } from '@react-email/components';
import type { EmailBrandProps } from './email-brand';
import { isPresent } from './present';
import { getActiveBeaconPalette, getActiveBeaconTokens } from './token-context';

export interface EmailFooterProps {
  brand: EmailBrandProps;
  recipientEmail?: string;
}

/**
 * Minimal in-card footer — single preference line + address.
 */
export function EmailFooter({ brand, recipientEmail }: EmailFooterProps) {
  const palette = getActiveBeaconPalette();
  const tokens = getActiveBeaconTokens();
  const preferencesUrl = brand.preferencesUrl ?? brand.unsubscribeUrl;
  const addressLine = [brand.legalName, brand.companyAddress].filter(isPresent).join(' · ');

  return (
    <Section
      style={{
        borderTop: `1px solid ${palette.border}`,
        backgroundColor: palette.surface,
        padding: '22px 36px',
        textAlign: 'center',
      }}
    >
      <Text
        style={{
          fontFamily: tokens.fontFamily.body,
          fontSize: 12,
          color: palette.mutedSoft,
          lineHeight: 1.5,
          margin: '0 0 4px',
        }}
      >
        {isPresent(recipientEmail) ? (
          <>
            Sent to <span style={{ color: palette.body }}>{recipientEmail}</span>
          </>
        ) : null}
        {isPresent(recipientEmail) && isPresent(preferencesUrl) ? ' · ' : null}
        {isPresent(preferencesUrl) ? (
          <Link href={preferencesUrl} style={{ color: palette.body, textDecoration: 'none' }}>
            Preferences
          </Link>
        ) : null}
        {isPresent(brand.termsUrl) ? (
          <>
            {' · '}
            <Link href={brand.termsUrl} style={{ color: palette.body, textDecoration: 'none' }}>
              Terms
            </Link>
          </>
        ) : null}
        {isPresent(brand.privacyUrl) ? (
          <>
            {' · '}
            <Link href={brand.privacyUrl} style={{ color: palette.body, textDecoration: 'none' }}>
              Privacy
            </Link>
          </>
        ) : null}
      </Text>
      {isPresent(addressLine) ? (
        <Text
          style={{
            fontFamily: tokens.fontFamily.body,
            fontSize: 11,
            color: palette.mutedSoft,
            lineHeight: 1.4,
            margin: 0,
          }}
        >
          {addressLine}
        </Text>
      ) : null}
    </Section>
  );
}

import { Column, Img, Row, Section, Text } from '@react-email/components';
import { LETTERKIT_LOGO_HEIGHT, LETTERKIT_LOGO_WIDTH, letterkitBrand } from '../../_brand';
import type { EmailBrandProps } from './email-brand';
import { isPresent } from './present';
import { getActiveBeaconPalette } from './token-context';

export interface EmailForestHeaderProps {
  brand: EmailBrandProps;
  stampLabel?: string;
  stampValue?: string;
}

/**
 * Forest brand block — centered logo, optional stamp row (label left, value right).
 */
export function EmailForestHeader({ brand, stampLabel, stampValue }: EmailForestHeaderProps) {
  const palette = getActiveBeaconPalette();
  const hasLogo = isPresent(brand.logoUrl);
  const hasName = isPresent(brand.appName);
  const logoAlt = brand.logoAlt ?? brand.appName ?? letterkitBrand.logoAlt;
  const hasStamp = isPresent(stampLabel) && isPresent(stampValue);

  return (
    <Section
      style={{
        backgroundColor: palette.forest,
        padding: hasStamp ? '24px 36px 20px' : '26px 36px',
      }}
    >
      <Row>
        <Column align="center" style={{ textAlign: 'center' }}>
          {hasLogo ? (
            <Img
              src={brand.logoUrl}
              width={LETTERKIT_LOGO_WIDTH}
              height={LETTERKIT_LOGO_HEIGHT}
              alt={logoAlt}
              style={{ display: 'block', margin: '0 auto' }}
            />
          ) : hasName ? (
            <Text
              style={{
                margin: 0,
                fontFamily: palette.fontFamily,
                fontSize: 15,
                fontWeight: 500,
                color: palette.forestText,
                textAlign: 'center',
              }}
            >
              {brand.appName}
            </Text>
          ) : null}
        </Column>
      </Row>

      {hasStamp ? (
        <Row style={{ marginTop: 16 }}>
          <Column align="left" style={{ verticalAlign: 'middle', width: '50%' }}>
            <Text
              style={{
                fontFamily: palette.fontMono,
                fontSize: 10,
                color: palette.forestMuted,
                margin: 0,
                textAlign: 'left',
              }}
            >
              {stampLabel}
            </Text>
          </Column>
          <Column align="right" style={{ verticalAlign: 'middle', width: '50%' }}>
            <Text
              style={{
                fontFamily: palette.fontMono,
                fontSize: 12,
                color: palette.forestText,
                margin: 0,
                textAlign: 'right',
              }}
            >
              {stampValue}
            </Text>
          </Column>
        </Row>
      ) : null}
    </Section>
  );
}

import { Heading, Section, Text } from '@react-email/components';
import type { ReactNode } from 'react';
import { getActiveBeaconPalette, getActiveBeaconTokens } from './token-context';

export interface EmailHeadingProps {
  children: ReactNode;
  subtitle?: string;
  /** Center only for billing-style hero headlines. */
  centered?: boolean;
}

export function EmailHeading({ children, subtitle, centered = false }: EmailHeadingProps) {
  const tokens = getActiveBeaconTokens();
  const palette = getActiveBeaconPalette();
  const align = centered ? 'center' : 'left';

  const content = (
    <>
      <Heading
        style={{
          color: palette.ink,
          fontFamily: tokens.fontFamily.heading,
          fontSize: tokens.fontSize['2xl'],
          fontWeight: 500,
          lineHeight: 1.2,
          margin: `0 0 ${subtitle ? 10 : tokens.spacing.md}`,
          textAlign: align,
        }}
      >
        {children}
      </Heading>
      {subtitle ? (
        <Text
          style={{
            color: palette.body,
            fontFamily: tokens.fontFamily.body,
            fontSize: tokens.fontSize.lg,
            lineHeight: 1.4,
            margin: '0 0 12px',
            textAlign: align,
          }}
        >
          {subtitle}
        </Text>
      ) : null}
    </>
  );

  if (centered) {
    return <Section style={{ marginBottom: 36 }}>{content}</Section>;
  }

  return <Section style={{ marginBottom: 16, textAlign: 'left' }}>{content}</Section>;
}

import { Column, Row, Section, Text } from '@react-email/components';
import { getActiveBeaconPalette, getActiveBeaconTokens } from './token-context';

export interface EmailHighlightListProps {
  title: string;
  items: string[];
}

/**
 * Digest highlights — forest title band + numbered rows.
 */
export function EmailHighlightList({ title, items }: EmailHighlightListProps) {
  const palette = getActiveBeaconPalette();
  const tokens = getActiveBeaconTokens();

  return (
    <Section
      style={{
        border: `1px solid ${palette.surfaceTint}`,
        borderRadius: 8,
        margin: '16px 0',
        overflow: 'hidden',
      }}
    >
      <Section style={{ backgroundColor: palette.forest, padding: '10px 18px' }}>
        <Text
          style={{
            color: palette.forestText,
            fontFamily: tokens.fontFamily.body,
            fontSize: 12,
            fontWeight: 500,
            margin: 0,
            textAlign: 'left',
          }}
        >
          {title}
        </Text>
      </Section>
      <Section style={{ backgroundColor: palette.card, padding: '4px 0' }}>
        {items.map((item, index) => (
          <Row key={`${item}-${index}`} style={{ padding: '10px 18px' }}>
            <Column style={{ verticalAlign: 'top', width: 28 }}>
              <Text
                style={{
                  color: palette.forest,
                  fontFamily: palette.fontMono,
                  fontSize: 11,
                  margin: 0,
                  textAlign: 'left',
                }}
              >
                {String(index + 1).padStart(2, '0')}
              </Text>
            </Column>
            <Column style={{ verticalAlign: 'top' }}>
              <Text
                style={{
                  color: palette.body,
                  fontFamily: tokens.fontFamily.body,
                  fontSize: 14,
                  lineHeight: '22px',
                  margin: 0,
                  textAlign: 'left',
                }}
              >
                {item}
              </Text>
            </Column>
          </Row>
        ))}
      </Section>
    </Section>
  );
}

import { Column, Row, Section, Text } from '@react-email/components';
import { getActiveBeaconPalette } from './token-context';

export interface InfoRow {
  label: string;
  value: string;
}

export interface EmailInfoCardProps {
  rows: InfoRow[];
}

export function EmailInfoCard({ rows }: EmailInfoCardProps) {
  const palette = getActiveBeaconPalette();

  return (
    <Section
      style={{
        backgroundColor: palette.surface,
        border: `1px solid ${palette.surfaceTint}`,
        borderRadius: 8,
        padding: '14px 18px',
        margin: '16px 0',
      }}
    >
      {rows.map((row, index) => (
        <Row key={row.label} style={{ paddingTop: index === 0 ? 0 : 6 }}>
          <Column align="left" style={{ verticalAlign: 'middle', width: '50%' }}>
            <Text
              style={{
                fontSize: 13,
                color: palette.body,
                margin: 0,
                textAlign: 'left',
              }}
            >
              {row.label}
            </Text>
          </Column>
          <Column align="right" style={{ verticalAlign: 'middle', width: '50%' }}>
            <Text
              style={{
                fontFamily: palette.fontMono,
                fontSize: 13,
                color: palette.ink,
                margin: 0,
                textAlign: 'right',
              }}
            >
              {row.value}
            </Text>
          </Column>
        </Row>
      ))}
    </Section>
  );
}

import {
  Body,
  Container,
  Font,
  Head,
  Html,
  Preview,
  Section,
} from '@react-email/components';
import type { ReactNode } from 'react';
import type { PartialBeaconTokens } from '../tokens.config';
import type { EmailBrandProps } from './email-brand';
import { withEmailBrandDefaults } from './email-brand';
import { EmailFooter } from './footer';
import { EmailForestHeader, type EmailForestHeaderProps } from './header';
import { resolveBeaconTokens, setActiveBeaconTokens } from './token-context';

export interface EmailLayoutProps {
  brand: EmailBrandProps;
  preview: string;
  tokens?: PartialBeaconTokens;
  recipientEmail?: string;
  forestHeader?: Pick<EmailForestHeaderProps, 'stampLabel' | 'stampValue'>;
  children: ReactNode;
}

/**
 * Beacon card shell — forest brand block, content, minimal in-card footer.
 */
export function EmailLayout({
  brand,
  preview,
  tokens,
  recipientEmail,
  forestHeader,
  children,
}: EmailLayoutProps) {
  const palette = resolveBeaconTokens(tokens);
  setActiveBeaconTokens(palette);
  const resolvedBrand = withEmailBrandDefaults(brand);

  return (
    <Html lang="en">
      <Head>
        <meta name="color-scheme" content="light only" />
        <meta name="supported-color-schemes" content="light" />
        <Font
          fontFamily="Geist"
          fallbackFontFamily={['Helvetica', 'Arial', 'sans-serif']}
          webFont={{
            url: 'https://fonts.gstatic.com/s/geist/v3/gyByhwUxId8gMEwYGFU8Nq8SXOzZWuP01vkmrMjlWdL_-jM.woff2',
            format: 'woff2',
          }}
          fontWeight={400}
          fontStyle="normal"
        />
        <Font
          fontFamily="Geist"
          fallbackFontFamily={['Helvetica', 'Arial', 'sans-serif']}
          webFont={{
            url: 'https://fonts.gstatic.com/s/geist/v3/gyByhwUxId8gMEwYGFU8Nq8SXOzZWuP01vkmrMjlWdL_-jM.woff2',
            format: 'woff2',
          }}
          fontWeight={500}
          fontStyle="normal"
        />
        <Font
          fontFamily="JetBrains Mono"
          fallbackFontFamily={['monospace']}
          webFont={{
            url: 'https://fonts.gstatic.com/s/jetbrainsmono/v20/tDbY2o-flEEny0FZhsfKu5WU4xD7OgnTzj0AY7HxQg.woff2',
            format: 'woff2',
          }}
          fontWeight={400}
          fontStyle="normal"
        />
      </Head>
      <Preview>{preview}</Preview>
      <Body
        style={{
          backgroundColor: palette.page,
          margin: 0,
          padding: '24px 16px',
          fontFamily: palette.fontFamily,
          color: palette.ink,
          WebkitFontSmoothing: 'antialiased',
        }}
      >
        <Container
          style={{
            maxWidth: 540,
            margin: '0 auto',
            backgroundColor: palette.card,
            borderRadius: 12,
            overflow: 'hidden',
            border: `1px solid ${palette.border}`,
          }}
        >
          <EmailForestHeader
            brand={resolvedBrand}
            stampLabel={forestHeader?.stampLabel}
            stampValue={forestHeader?.stampValue}
          />
          <Section style={{ padding: '32px 36px 28px', textAlign: 'left' }}>{children}</Section>
          <EmailFooter brand={resolvedBrand} recipientEmail={recipientEmail} />
        </Container>
      </Body>
    </Html>
  );
}

import { Column, Row, Section, Text } from '@react-email/components';
import { getActiveBeaconPalette } from './token-context';

export interface LineItem {
  description?: string;
  name?: string;
  detail?: string;
  amount: string;
}

export interface EmailLineItemsProps {
  items: LineItem[];
  title?: string;
}

export function EmailLineItems({ items, title }: EmailLineItemsProps) {
  const palette = getActiveBeaconPalette();

  return (
    <Section style={{ borderTop: title ? undefined : `1px solid ${palette.border}`, paddingTop: title ? 0 : 16 }}>
      {title ? (
        <Text
          style={{
            color: palette.ink,
            fontSize: 12,
            fontWeight: 500,
            margin: '0 0 12px',
            textAlign: 'left',
          }}
        >
          {title}
        </Text>
      ) : null}
      {items.map((item, index) => {
        const label = item.description ?? item.name ?? '';
        return (
          <Row key={`${label}-${index}`} style={{ padding: '6px 0' }}>
            <Column align="left" style={{ verticalAlign: 'middle', width: '68%' }}>
              <Text style={{ fontSize: 14, color: palette.ink, margin: 0, textAlign: 'left' }}>
                {label}
              </Text>
              {item.detail ? (
                <Text
                  style={{
                    fontSize: 12,
                    color: palette.muted,
                    margin: '4px 0 0',
                    textAlign: 'left',
                  }}
                >
                  {item.detail}
                </Text>
              ) : null}
            </Column>
            <Column align="right" style={{ verticalAlign: 'middle', width: '32%' }}>
              <Text
                style={{
                  fontFamily: palette.fontMono,
                  fontSize: 14,
                  color: palette.ink,
                  margin: 0,
                  textAlign: 'right',
                }}
              >
                {item.amount}
              </Text>
            </Column>
          </Row>
        );
      })}
    </Section>
  );
}

import { Link, Section, Text } from '@react-email/components';
import { getActiveBeaconTokens } from './token-context';

export interface EmailLinkFallbackProps {
  url: string;
  label?: string;
}

/**
 * Monospace URL fallback block for clients that strip buttons.
 */
export function EmailLinkFallback({ url, label = 'Or copy this link' }: EmailLinkFallbackProps) {
  const tokens = getActiveBeaconTokens();

  return (
    <Section style={{ marginTop: tokens.spacing.md }}>
      <Text
        className="email-muted"
        style={{
          color: tokens.colors.mutedForeground,
          fontSize: tokens.fontSize.xs,
          margin: `0 0 ${tokens.spacing.xs}`,
        }}
      >
        {label}
      </Text>
      <Section
        className="email-accent"
        style={{
          backgroundColor: tokens.colors.muted,
          border: `1px solid ${tokens.colors.border}`,
          borderRadius: 0,
          padding: `${tokens.spacing.sm} ${tokens.spacing.md}`,
        }}
      >
        <Link
          href={url}
          style={{
            color: tokens.colors.foreground,
            fontFamily: tokens.fontFamily.mono,
            fontSize: tokens.fontSize.xs,
            lineHeight: '18px',
            textDecoration: 'none',
            wordBreak: 'break-all',
          }}
        >
          {url}
        </Link>
      </Section>
    </Section>
  );
}

export function isPresent(value: string | undefined | null): value is string {
  return typeof value === 'string' && value.trim().length > 0;
}

import { Column, Row, Section, Text } from '@react-email/components';
import type { ReactNode } from 'react';
import { getActiveBeaconPalette, getActiveBeaconTokens } from './token-context';

export interface EmailSnippetPanelProps {
  author: string;
  children: ReactNode;
  /** Right-column stamp label (e.g. Thread, Channel). */
  stampLabel?: string;
  /** Right-column stamp value. Falls back to `context` when omitted. */
  stampValue?: string;
  /** @deprecated Use stampLabel + stampValue. */
  context?: string;
  footnote?: string;
}

/**
 * Message excerpt — mini forest stamp header + quote body (no side borders).
 */
export function EmailSnippetPanel({
  author,
  children,
  stampLabel = 'Thread',
  stampValue,
  context,
  footnote,
}: EmailSnippetPanelProps) {
  const palette = getActiveBeaconPalette();
  const tokens = getActiveBeaconTokens();
  const resolvedStamp = stampValue ?? context;

  return (
    <Section
      style={{
        border: `1px solid ${palette.surfaceTint}`,
        borderRadius: 8,
        margin: '16px 0',
        overflow: 'hidden',
      }}
    >
      <Section style={{ backgroundColor: palette.forest, padding: '12px 18px' }}>
        <Row>
          <Column align="left" style={{ verticalAlign: 'middle', width: '50%' }}>
            <Text
              style={{
                color: palette.forestMuted,
                fontFamily: palette.fontMono,
                fontSize: 10,
                margin: '0 0 4px',
                textAlign: 'left',
              }}
            >
              From
            </Text>
            <Text
              style={{
                color: palette.forestText,
                fontFamily: palette.fontMono,
                fontSize: 12,
                margin: 0,
                textAlign: 'left',
              }}
            >
              {author}
            </Text>
          </Column>
          {resolvedStamp ? (
            <Column align="right" style={{ verticalAlign: 'middle', width: '50%' }}>
              <Text
                style={{
                  color: palette.forestMuted,
                  fontFamily: palette.fontMono,
                  fontSize: 10,
                  margin: '0 0 4px',
                  textAlign: 'right',
                }}
              >
                {stampLabel}
              </Text>
              <Text
                style={{
                  color: palette.forestText,
                  fontFamily: palette.fontMono,
                  fontSize: 12,
                  margin: 0,
                  textAlign: 'right',
                }}
              >
                {resolvedStamp}
              </Text>
            </Column>
          ) : null}
        </Row>
      </Section>
      <Section style={{ backgroundColor: palette.card, padding: '16px 18px' }}>
        <Text
          style={{
            color: palette.ink,
            fontFamily: tokens.fontFamily.body,
            fontSize: 15,
            lineHeight: '24px',
            margin: 0,
            textAlign: 'left',
          }}
        >
          {children}
        </Text>
        {footnote ? (
          <Text
            style={{
              color: palette.muted,
              fontFamily: palette.fontMono,
              fontSize: 11,
              margin: '10px 0 0',
              textAlign: 'left',
            }}
          >
            {footnote}
          </Text>
        ) : null}
      </Section>
    </Section>
  );
}

import type { ThemeTokens } from '@letterkit/theme';
import {
  beaconPaletteToThemeTokens,
  beaconTokens,
  mergeBeaconTokens,
  type BeaconPaletteTokens,
  type PartialBeaconTokens,
} from '../tokens.config';

let activePalette: BeaconPaletteTokens = beaconTokens;
let activeThemeTokens: ThemeTokens = beaconPaletteToThemeTokens(beaconTokens);

/** Set palette for the current email render (called by EmailLayout). */
export function setActiveBeaconTokens(palette: BeaconPaletteTokens): void {
  activePalette = palette;
  activeThemeTokens = beaconPaletteToThemeTokens(palette);
}

export function getActiveBeaconPalette(): BeaconPaletteTokens {
  return activePalette;
}

export function getActiveBeaconTokens(): ThemeTokens {
  return activeThemeTokens;
}

export function resolveBeaconTokens(override?: PartialBeaconTokens): BeaconPaletteTokens {
  return mergeBeaconTokens(beaconTokens, override);
}

import { Column, Row, Section, Text } from '@react-email/components';
import { getActiveBeaconPalette } from './token-context';

export interface TotalRow {
  label: string;
  value: string;
  emphasis?: boolean;
  muted?: boolean;
}

export interface EmailTotalsProps {
  rows?: TotalRow[];
  totalLabel?: string;
  totalValue?: string;
}

export function EmailTotals({ rows = [], totalLabel = 'Total charged', totalValue }: EmailTotalsProps) {
  const palette = getActiveBeaconPalette();

  if (totalValue) {
    const mutedRows = rows.filter((row) => !row.emphasis);
    return (
      <Section>
        {mutedRows.length > 0 ? (
          <Section
            style={{
              borderTop: `1px solid ${palette.border}`,
              marginTop: 10,
              paddingTop: 12,
            }}
          >
            {mutedRows.map((row) => (
              <Row key={row.label} style={{ padding: '5px 0' }}>
                <Column align="left" style={{ verticalAlign: 'middle', width: '50%' }}>
                  <Text style={{ fontSize: 13, color: palette.muted, margin: 0, textAlign: 'left' }}>
                    {row.label}
                  </Text>
                </Column>
                <Column align="right" style={{ verticalAlign: 'middle', width: '50%' }}>
                  <Text
                    style={{
                      fontFamily: palette.fontMono,
                      fontSize: 13,
                      color: palette.muted,
                      margin: 0,
                      textAlign: 'right',
                    }}
                  >
                    {row.value}
                  </Text>
                </Column>
              </Row>
            ))}
          </Section>
        ) : null}

        <Section
          style={{
            borderTop: `2px solid ${palette.forest}`,
            marginTop: 10,
            paddingTop: 16,
          }}
        >
          <Row>
            <Column align="left" style={{ verticalAlign: 'baseline', width: '50%' }}>
              <Text style={{ fontSize: 15, fontWeight: 500, color: palette.ink, margin: 0, textAlign: 'left' }}>
                {totalLabel}
              </Text>
            </Column>
            <Column align="right" style={{ verticalAlign: 'baseline', width: '50%' }}>
              <Text
                style={{
                  fontFamily: palette.fontMono,
                  fontSize: 22,
                  fontWeight: 500,
                  color: palette.forest,
                  margin: 0,
                  textAlign: 'right',
                }}
              >
                {totalValue}
              </Text>
            </Column>
          </Row>
        </Section>
      </Section>
    );
  }

  return (
    <Section style={{ marginTop: 10 }}>
      {rows.map((row) => (
        <Row
          key={row.label}
          style={{
            borderTop: row.emphasis ? `2px solid ${palette.forest}` : undefined,
            marginTop: row.emphasis ? 10 : 0,
            padding: '8px 0',
          }}
        >
          <Column align="left" style={{ width: '65%', verticalAlign: 'middle' }}>
            <Text
              style={{
                color: row.emphasis ? palette.ink : palette.muted,
                fontSize: row.emphasis ? 15 : 13,
                fontWeight: row.emphasis ? 500 : 400,
                margin: 0,
                textAlign: 'left',
              }}
            >
              {row.label}
            </Text>
          </Column>
          <Column align="right" style={{ width: '35%', verticalAlign: 'middle' }}>
            <Text
              style={{
                color: row.emphasis ? palette.forest : palette.muted,
                fontFamily: palette.fontMono,
                fontSize: row.emphasis ? 22 : 13,
                fontWeight: row.emphasis ? 500 : 400,
                margin: 0,
                textAlign: 'right',
              }}
            >
              {row.value}
            </Text>
          </Column>
        </Row>
      ))}
    </Section>
  );
}

import type { EmailBrandProps } from './_components/email-brand';

export const beaconBrand: EmailBrandProps = {
  appName: 'letterkit',
  websiteUrl: 'acme.com',
  unsubscribeUrl: 'https://app.acme.com/preferences',
  termsUrl: 'https://acme.com/terms',
  privacyUrl: 'https://acme.com/privacy',
  legalName: 'Acme Inc',
  companyAddress: '350 Mission St, San Francisco',
  supportUrl: 'https://acme.com/support',
  copyrightYear: 2026,
};

import type { ThemeTokens } from '@letterkit/theme';

/**
 * Design tokens — configure once, every Beacon email inherits this palette.
 * Forest signature for fintech / billing. Flat keys match the Try panel fields.
 */
export interface BeaconPaletteTokens {
  page: string;
  card: string;
  surface: string;
  surfaceTint: string;
  ink: string;
  body: string;
  muted: string;
  mutedSoft: string;
  border: string;
  forest: string;
  forestSoft: string;
  forestText: string;
  forestMuted: string;
  fontFamily: string;
  fontMono: string;
  /** Try panel alias → forest */
  accent: string;
  accentForeground: string;
}

export type PartialBeaconTokens = Partial<BeaconPaletteTokens>;

export const beaconTokens: BeaconPaletteTokens = {
  page: '#F5F1E8',
  card: '#FFFFFF',
  surface: '#FAFAF7',
  surfaceTint: '#EFEDE8',
  ink: '#0A0A0A',
  body: '#57534E',
  muted: '#78716C',
  mutedSoft: '#A8A29E',
  border: '#E7E5E4',
  forest: '#0F3D2E',
  forestSoft: '#1A5240',
  forestText: '#F5EFE0',
  forestMuted: '#8FA89C',
  fontFamily: '"Geist", -apple-system, BlinkMacSystemFont, "Segoe UI", Helvetica, Arial, sans-serif',
  fontMono: '"JetBrains Mono", ui-monospace, SFMono-Regular, Menlo, monospace',
  accent: '#0F3D2E',
  accentForeground: '#F5EFE0',
};

const BEACON_THEME_STRUCTURE = {
  spacing: {
    xs: '4px',
    sm: '8px',
    md: '16px',
    lg: '24px',
    xl: '32px',
    '2xl': '48px',
  },
  radius: {
    sm: '6px',
    md: '8px',
    lg: '12px',
    full: '9999px',
  },
  fontFamily: {
    heading: beaconTokens.fontFamily,
    body: beaconTokens.fontFamily,
    mono: beaconTokens.fontMono,
  },
  fontSize: {
    xs: '11px',
    sm: '12px',
    base: '14px',
    lg: '15px',
    xl: '22px',
    '2xl': '28px',
  },
} as const satisfies Pick<ThemeTokens, 'spacing' | 'radius' | 'fontFamily' | 'fontSize'>;

export function beaconPaletteToThemeTokens(palette: BeaconPaletteTokens): ThemeTokens {
  return {
    colors: {
      background: palette.card,
      foreground: palette.ink,
      muted: palette.surface,
      mutedForeground: palette.muted,
      primary: palette.forest,
      primaryForeground: palette.forestText,
      accent: palette.surfaceTint,
      accentForeground: palette.ink,
      border: palette.border,
    },
    ...BEACON_THEME_STRUCTURE,
    fontFamily: {
      ...BEACON_THEME_STRUCTURE.fontFamily,
      body: palette.fontFamily,
      mono: palette.fontMono,
    },
  };
}

export function mergeBeaconTokens(
  base: BeaconPaletteTokens,
  override?: PartialBeaconTokens,
): BeaconPaletteTokens {
  return { ...base, ...override };
}

import type { ThemeConfig } from '@letterkit/theme';
import { beaconPaletteToThemeTokens, beaconTokens } from './tokens.config';

export const beacon: ThemeConfig = {
  id: 'beacon',
  name: 'Beacon',
  tagline: 'For SaaS that handles money like it matters.',
  description:
    'Premium fintech feel. Forest signature, mono numerals, structured billing layouts. Built for receipts, invoices, and payment lifecycle.',
  author: 'letterkit',
  tier: 'pro',
  tokens: beaconPaletteToThemeTokens(beaconTokens),
};

export default beacon;

