export interface NewDeviceLoginProps {
  brand?: EmailBrandProps;
  tokens?: PartialBeaconTokens;
  recipientEmail?: string;
  userName: string;
  activityUrl: string;
  device: string;
  ipAddress: string;
  location?: string;
  loggedInAt: string;
}

/**
 * New device login alert template for the Beacon theme.
 */
export function NewDeviceLogin({
  brand = beaconBrand,
  tokens,
  recipientEmail,
  userName,
  activityUrl,
  device,
  ipAddress,
  location,
  loggedInAt,
}: NewDeviceLoginProps) {
