export interface OtpCodeProps {
  brand?: EmailBrandProps;
  tokens?: PartialBeaconTokens;
  recipientEmail?: string;
  userName: string;
  verificationCode: string;
  expiresIn: string;
  ipAddress?: string;
  location?: string;
  attemptedAt?: string;
}

/**
 * One-time passcode template for the Beacon theme.
 */
export function OtpCode({
  brand = beaconBrand,
  tokens,
  recipientEmail,
  userName,
  verificationCode,
  expiresIn,
  ipAddress,
  location,
  attemptedAt,
}: OtpCodeProps) {
  const appName = brand.appName;

  return (
    <EmailLayout
      brand={brand}
      tokens={tokens}
