        {label}
      </Text>
      <Text
        style={{
          color: highlight ? t.colors.primary : '#9CA3AF',
          fontSize: t.fontSize.base,
          fontWeight: highlight ? 600 : 400,
          lineHeight: '24px',
          margin: 0,
        }}
      >
        {value}
      </Text>
