import { resolveGrundyTokens, setActiveGrundyTokens } from './token-context';

export interface EmailLayoutProps {
  brand: EmailBrandProps;
  preview: string;
  tokens?: PartialGrundyTokens;
  recipientEmail?: string;
  headerTagline?: string;
  helpEmail?: string;
  children: ReactNode;
}

/**
 * Root email layout with Grundy accent bar, card shell, header, and footer.
 */
export function EmailLayout({
  brand,
  preview,
  tokens,
  recipientEmail,
  headerTagline,
  helpEmail,
  children,
}: EmailLayoutProps) {
  const resolved = resolveGrundyTokens(tokens);
  setActiveGrundyTokens(resolved);
  const t = withEmailBrandDefaults(brand);

  return (
    <Tailwind>
      <Html lang="en">
        <Head>
          <link
            href="https://fonts.googleapis.com/css2?family=Fraunces:opsz,wght@9..144,400;9..144,600;9..144,700&display=swap"
            rel="stylesheet"
          />
          <style>{`
            @media (prefers-color-scheme: dark) {
              .email-bg { background-color: #141414 !important; }
              .email-shell { background-color: #1A1A1A !important; }
              .email-fg { color: #FAF8F3 !important; }
              .email-muted { color: #A8A29E !important; }
              .email-border { border-color: #3D3A36 !important; }
              .email-accent { background-color: #2A2826 !important; }
              .email-btn { background-color: #C44536 !important; color: #FAF8F3 !important; }
            }
          `}</style>
        </Head>
        <Preview>{preview}</Preview>
        <Body
          className="email-bg"
          style={{
            backgroundColor: resolved.page,
            fontFamily: resolved.fontFamily,
            margin: 0,
            padding: '24px 16px',
          }}
        >
          <Container style={{ maxWidth: '560px', margin: '0 auto' }}>
            <EmailHeader brand={t} tagline={headerTagline} />
            <Section
              className="email-shell email-border"
              style={{
                backgroundColor: resolved.card,
                border: `1px solid ${resolved.border}`,
                borderRadius: 0,
                boxShadow: '0 1px 2px rgba(26, 26, 26, 0.04)',
                overflow: 'hidden',
              }}
            >
              <Section
                style={{
                  backgroundColor: resolved.accent,
                  height: '3px',
                  lineHeight: '3px',
                }}
              >
                <span style={{ fontSize: '1px' }}>&nbsp;</span>
              </Section>
              <Section style={{ padding: '32px 32px 24px' }}>{children}</Section>
            </Section>
            <EmailFooter
              brand={t}
              recipientEmail={recipientEmail}
              helpEmail={helpEmail}
            />
          </Container>
        </Body>
      </Html>
    </Tailwind>
  );
}

import { Column, Row, Section, Text } from '@react-email/components';
import { getActiveGrundyTokens } from './token-context';

export interface LineItem {
  name: string;
  detail?: string;
  amount: string;
}

export interface EmailLineItemsProps {
  items: LineItem[];
  title?: string;
}

/**
 * Itemized list for invoices, orders, and digests.
 */
export function EmailLineItems({ items, title }: EmailLineItemsProps) {
  const tokens = getActiveGrundyTokens();

  return (
    <Section style={{ margin: `${tokens.spacing.lg} 0` }}>
      {title ? (
        <Text
          style={{
            borderBottom: `2px solid ${tokens.colors.foreground}`,
            color: tokens.colors.foreground,
            fontSize: tokens.fontSize.xs,
            fontWeight: 600,
            margin: `0 0 ${tokens.spacing.md}`,
            paddingBottom: tokens.spacing.xs,
          }}
        >
          {title}
        </Text>
      ) : null}
      {items.map((item, index) => (
        <Row
          key={`${item.name}-${index}`}
          className="email-border"
          style={{
            borderBottom: `1px solid ${tokens.colors.border}`,
            padding: `${tokens.spacing.sm} 0`,
          }}
        >
          <Column style={{ width: '68%', verticalAlign: 'top' }}>
            <Text
              style={{
                color: tokens.colors.foreground,
                fontSize: tokens.fontSize.sm,
                fontWeight: 600,
                margin: `0 0 ${item.detail ? tokens.spacing.xs : 0}`,
              }}
            >
              {item.name}
            </Text>
            {item.detail ? (
              <Text
                className="email-muted"
                style={{
                  color: tokens.colors.mutedForeground,
                  fontSize: tokens.fontSize.xs,
                  margin: 0,
                }}
              >
                {item.detail}
              </Text>
            ) : null}
          </Column>
          <Column style={{ width: '32%', textAlign: 'right', verticalAlign: 'top' }}>
            <Text
              style={{
                color: tokens.colors.foreground,
                fontFamily: tokens.fontFamily.mono,
                fontSize: tokens.fontSize.sm,
                fontWeight: 600,
                margin: 0,
              }}
            >
              {item.amount}
            </Text>
          </Column>
        </Row>
      ))}
    </Section>
  );
}

import { Link, Section, Text } from '@react-email/components';
import { getActiveGrundyTokens } from './token-context';

export interface EmailLinkFallbackProps {
  url: string;
  label?: string;
}

/**
 * Monospace URL fallback block for clients that strip buttons.
 */
export function EmailLinkFallback({ url, label = 'Or copy this link' }: EmailLinkFallbackProps) {
  const tokens = getActiveGrundyTokens();

  return (
    <Section style={{ marginTop: tokens.spacing.md }}>
      <Text
        className="email-muted"
        style={{
          color: tokens.colors.mutedForeground,
          fontSize: tokens.fontSize.xs,
          margin: `0 0 ${tokens.spacing.xs}`,
        }}
      >
        {label}
      </Text>
      <Section
        className="email-accent"
        style={{
          backgroundColor: tokens.colors.muted,
          border: `1px solid ${tokens.colors.border}`,
          borderRadius: 0,
          padding: `${tokens.spacing.sm} ${tokens.spacing.md}`,
        }}
      >
        <Link
          href={url}
          style={{
            color: tokens.colors.foreground,
            fontFamily: tokens.fontFamily.mono,
            fontSize: tokens.fontSize.xs,
            lineHeight: '18px',
            textDecoration: 'none',
            wordBreak: 'break-all',
          }}
        >
          {url}
        </Link>
      </Section>
    </Section>
  );
}

export function isPresent(value: string | undefined | null): value is string {
  return typeof value === 'string' && value.trim().length > 0;
}

import type { ThemeTokens } from '@letterkit/theme';
import {
  grundyPaletteToThemeTokens,
  grundyTokens,
  mergeGrundyTokens,
  type GrundyPaletteTokens,
  type PartialGrundyTokens,
} from '../tokens.config';

let activePalette: GrundyPaletteTokens = grundyTokens;
let activeThemeTokens: ThemeTokens = grundyPaletteToThemeTokens(grundyTokens);

/** Set palette for the current email render (called by EmailLayout). */
export function setActiveGrundyTokens(palette: GrundyPaletteTokens): void {
  activePalette = palette;
  activeThemeTokens = grundyPaletteToThemeTokens(palette);
}

export function getActiveGrundyPalette(): GrundyPaletteTokens {
  return activePalette;
}

export function getActiveGrundyTokens(): ThemeTokens {
  return activeThemeTokens;
}

export function resolveGrundyTokens(override?: PartialGrundyTokens): GrundyPaletteTokens {
  return mergeGrundyTokens(grundyTokens, override);
}

import { Column, Row, Section, Text } from '@react-email/components';
import { getActiveGrundyTokens } from './token-context';

export interface TotalRow {
  label: string;
  value: string;
  emphasis?: boolean;
}

export interface EmailTotalsProps {
  rows: TotalRow[];
}

/**
 * Summary totals section with optional emphasized final row.
 */
export function EmailTotals({ rows }: EmailTotalsProps) {
  const tokens = getActiveGrundyTokens();

  return (
    <Section style={{ margin: `${tokens.spacing.md} 0` }}>
      {rows.map((row) => (
        <Row
          key={row.label}
          style={{
            borderTop: row.emphasis ? `2px solid ${tokens.colors.foreground}` : undefined,
            marginTop: row.emphasis ? tokens.spacing.sm : 0,
            padding: `${tokens.spacing.xs} 0`,
          }}
        >
          <Column style={{ width: '65%' }}>
            <Text
              style={{
                color: row.emphasis ? tokens.colors.foreground : tokens.colors.mutedForeground,
                fontSize: row.emphasis ? tokens.fontSize.base : tokens.fontSize.sm,
                fontWeight: row.emphasis ? 600 : 400,
                margin: 0,
              }}
            >
              {row.label}
            </Text>
          </Column>
          <Column style={{ width: '35%', textAlign: 'right' }}>
            <Text
              style={{
                color: tokens.colors.foreground,
                fontFamily: row.emphasis ? tokens.fontFamily.mono : tokens.fontFamily.body,
                fontSize: row.emphasis ? tokens.fontSize.lg : tokens.fontSize.sm,
                fontWeight: row.emphasis ? 600 : 400,
                margin: 0,
              }}
            >
              {row.value}
            </Text>
          </Column>
        </Row>
      ))}
    </Section>
  );
}

import type { ThemeTokens } from '@letterkit/theme';

/**
 * Design tokens — configure once, every Grundy email inherits this palette.
 * Maps to ThemeTokens for rendering; flat keys match the Try panel lifecycle fields.
 */
export interface GrundyPaletteTokens {
  page: string;
  card: string;
  ink: string;
  body: string;
  muted: string;
  mutedSoft: string;
  border: string;
  accent: string;
  accentForeground: string;
  fontFamily: string;
  successDot: string;
  successBg: string;
  successText: string;
  warningDot: string;
  warningBg: string;
  warningText: string;
  dangerDot: string;
  dangerBg: string;
  dangerText: string;
  neutralBadgeBg: string;
}

export type PartialGrundyTokens = Partial<GrundyPaletteTokens>;

export const grundyTokens: GrundyPaletteTokens = {
  page: '#FAF8F3',
  card: '#FAF8F3',
  ink: '#1A1A1A',
  body: '#1A1A1A',
  muted: '#6B6560',
  mutedSoft: '#6B6560',
  border: '#D9D4C8',
  accent: '#C44536',
  accentForeground: '#FAF8F3',
  fontFamily:
    '-apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, "Helvetica Neue", Arial, sans-serif',
  successDot: '#2D6A4F',
  successBg: '#E8F0EB',
  successText: '#1B4332',
  warningDot: '#B45309',
  warningBg: '#FEF3C7',
  warningText: '#92400E',
  dangerDot: '#C44536',
  dangerBg: '#FCEAE8',
  dangerText: '#9B2C2C',
  neutralBadgeBg: '#F0EDE6',
};

const GRUNDY_THEME_STRUCTURE = {
  spacing: {
    xs: '4px',
    sm: '8px',
    md: '16px',
    lg: '24px',
    xl: '32px',
    '2xl': '48px',
  },
    radius: {
      sm: '0px',
      md: '0px',
      lg: '0px',
      full: '0px',
    },
  fontFamily: {
    heading: '"Fraunces", Georgia, "Times New Roman", serif',
    body: grundyTokens.fontFamily,
    mono: 'ui-monospace, SFMono-Regular, "SF Mono", Menlo, Consolas, monospace',
  },
  fontSize: {
    xs: '11px',
    sm: '13px',
    base: '15px',
    lg: '17px',
    xl: '20px',
    '2xl': '26px',
  },
} as const satisfies Pick<ThemeTokens, 'spacing' | 'radius' | 'fontFamily' | 'fontSize'>;

export function grundyPaletteToThemeTokens(palette: GrundyPaletteTokens): ThemeTokens {
  return {
    colors: {
      background: palette.card,
      foreground: palette.ink,
      muted: '#F0EDE6',
      mutedForeground: palette.muted,
      primary: palette.accent,
      primaryForeground: palette.accentForeground,
      accent: '#E8E4DB',
      accentForeground: palette.ink,
      border: palette.border,
    },
    ...GRUNDY_THEME_STRUCTURE,
    fontFamily: {
      ...GRUNDY_THEME_STRUCTURE.fontFamily,
      body: palette.fontFamily,
    },
  };
}

export function mergeGrundyTokens(
  base: GrundyPaletteTokens,
  override?: PartialGrundyTokens,
): GrundyPaletteTokens {
  return { ...base, ...override };
}

import type { ThemeConfig } from '@letterkit/theme';
import { grundyPaletteToThemeTokens, grundyTokens } from './tokens.config';

export const grundy: ThemeConfig = {
  id: 'grundy',
  name: 'Grundy',
  tagline: 'Quiet, confident, modern.',
  description:
    'A minimal serif-meets-mono theme with cream backgrounds, ink typography, and terracotta accents. Typography-driven, no illustrations.',
  author: 'letterkit',
  tier: 'free',
  tokens: grundyPaletteToThemeTokens(grundyTokens),
};

export default grundy;

