export interface NewDeviceLoginProps {
  brand?: EmailBrandProps;
  tokens?: PartialGrundyTokens;
  recipientEmail?: string;
  userName: string;
  activityUrl: string;
  device: string;
  ipAddress: string;
  location?: string;
  loggedInAt: string;
}

/**
 * New device login alert template for the Grundy theme.
 */
export function NewDeviceLogin({
  brand = grundyBrand,
  tokens,
  recipientEmail,
  userName,
  activityUrl,
  device,
  ipAddress,
  location,
  loggedInAt,
}: NewDeviceLoginProps) {
