import { Link, Text } from '@react-email/components';
import type { ThemeTokens } from '@letterkit/theme';
import type { ReactNode } from 'react';

export interface EmailAsideProps {
  tokens: ThemeTokens;
  children: ReactNode;
  helpEmail?: string;
}

export function EmailAside({ tokens, children, helpEmail }: EmailAsideProps) {
  const linkStyle = { color: tokens.colors.primary, textDecoration: 'none' };

  return (
    <Text
      style={{
        color: '#9CA3AF',
        fontFamily: tokens.fontFamily.body,
        fontSize: tokens.fontSize.sm,
        lineHeight: '22px',
        margin: '0 0 8px',
        textAlign: 'left',
      }}
    >
      {children}
      {helpEmail ? (
        <>
          {' '}
          <Link href={`mailto:${helpEmail}`} style={linkStyle}>
            {helpEmail}
          </Link>
        </>
      ) : null}
    </Text>
  );
}

import { Text } from '@react-email/components';
import type { ThemeTokens } from '@letterkit/theme';
import type { ReactNode } from 'react';

export interface EmailBodyTextProps {
  tokens: ThemeTokens;
  children: ReactNode;
  muted?: boolean;
}

export function EmailBodyText({ tokens, children, muted = true }: EmailBodyTextProps) {
  return (
    <Text
      style={{
        color: muted ? tokens.colors.mutedForeground : tokens.colors.foreground,
        fontFamily: tokens.fontFamily.body,
        fontSize: tokens.fontSize.base,
        fontWeight: 400,
        lineHeight: '28px',
        margin: '0 0 28px',
        textAlign: 'left',
      }}
    >
      {children}
    </Text>
  );
}

import { Button as EmailButton } from '@react-email/components';
import type { ThemeTokens } from '@letterkit/theme';
import type { ReactNode } from 'react';

export interface EmailButtonProps {
  tokens: ThemeTokens;
  href: string;
  children: ReactNode;
}

/**
 * Primary CTA — PAYTORE-style blue pill button.
 */
export function EmailButtonLink({ tokens, href, children }: EmailButtonProps) {
  const t = tokens;

  return (
    <EmailButton
      href={href}
      style={{
        backgroundColor: t.colors.primary,
        borderRadius: t.radius.md,
        color: t.colors.primaryForeground,
        display: 'inline-block',
        fontFamily: t.fontFamily.body,
        fontSize: t.fontSize.base,
        fontWeight: 700,
        lineHeight: '24px',
        padding: '14px 32px',
        textAlign: 'center',
        textDecoration: 'none',
      }}
    >
      {children}
    </EmailButton>
  );
}

import { Body, Container, Head, Html, Preview, Section } from '@react-email/components';
import type { ThemeTokens } from '@letterkit/theme';
import type { ReactNode } from 'react';
import { senseiCanvas } from '../theme.config';
import { type EmailBrandProps, withEmailBrandDefaults } from './email-brand';
import { EmailFooter } from './footer';
import { EmailHeader } from './header';

export interface EmailCardLayoutProps {
  tokens: ThemeTokens;
  preview: string;
  brand: EmailBrandProps;
  children: ReactNode;
}

/**
 * Premium card layout — black canvas, white card, left-aligned content.
 * Pass shell props via `brand`; email body props stay on the template component.
 */
export function EmailCardLayout({ tokens, preview, brand, children }: EmailCardLayoutProps) {
  const t = tokens;
  const b = withEmailBrandDefaults(brand);

  return (
    <Html lang="en">
      <Head />
      <Preview>{preview}</Preview>
      <Body
        style={{
          backgroundColor: senseiCanvas,
          fontFamily: t.fontFamily.body,
          margin: 0,
          padding: '48px 16px',
        }}
      >
        <Container style={{ maxWidth: '520px', margin: '0 auto' }}>
          <Section
            style={{
              backgroundColor: t.colors.background,
              borderRadius: t.radius.lg,
              padding: '48px 40px 40px',
              textAlign: 'left',
            }}
          >
            <EmailHeader tokens={t} appName={b.appName} logoUrl={b.logoUrl} logoAlt={b.logoAlt} />
            <Section style={{ padding: '8px 0 0' }}>{children}</Section>
            <EmailFooter
              tokens={t}
              appName={b.appName}
              websiteUrl={b.websiteUrl}
              unsubscribeUrl={b.unsubscribeUrl}
              termsUrl={b.termsUrl}
              privacyUrl={b.privacyUrl}
              legalName={b.legalName}
              copyrightYear={b.copyrightYear}
            />
          </Section>
        </Container>
      </Body>
    </Html>
  );
}

import { Section, Text } from '@react-email/components';
import type { ThemeTokens } from '@letterkit/theme';

export interface EmailChecklistProps {
  tokens: ThemeTokens;
  items: string[];
}

/** Confirmed steps or security improvements — 2FA enabled, recovery setup. */
export function EmailChecklist({ tokens, items }: EmailChecklistProps) {
  const t = tokens;

  return (
    <Section style={{ margin: '0 0 28px', textAlign: 'left' }}>
      {items.map((item) => (
        <Text
          key={item}
          style={{
            color: t.colors.foreground,
            fontFamily: t.fontFamily.body,
            fontSize: t.fontSize.base,
            lineHeight: '28px',
            margin: '0 0 4px',
          }}
        >
          <span style={{ color: t.colors.primary, fontWeight: 700 }}>✓</span> {item}
        </Text>
      ))}
    </Section>
  );
}

import { Hr, Section, Text } from '@react-email/components';
import type { ThemeTokens } from '@letterkit/theme';

export interface EmailCodeDisplayProps {
  tokens: ThemeTokens;
  code: string;
  expiresIn?: string;
}

/** OTP focal point — large type between dividers, no gray box. */
export function EmailCodeDisplay({ tokens, code, expiresIn }: EmailCodeDisplayProps) {
  const t = tokens;
  const rule = {
    border: 'none',
    borderTop: `1px solid ${t.colors.border}`,
    margin: '28px 0',
  };

  return (
    <Section style={{ margin: '0 0 8px', textAlign: 'left' }}>
      <Hr style={rule} />
      <Text
        style={{
          color: t.colors.mutedForeground,
          fontFamily: t.fontFamily.body,
          fontSize: t.fontSize.base,
          fontWeight: 700,
          lineHeight: '24px',
          margin: '0 0 12px',
        }}
      >
        Your code
      </Text>
      <Text
        style={{
          color: t.colors.primary,
          fontFamily: t.fontFamily.mono,
          fontSize: '42px',
          fontWeight: 700,
          letterSpacing: '0.14em',
          lineHeight: '52px',
          margin: '0 0 8px',
        }}
      >
        {code}
      </Text>
      {expiresIn ? (
        <Text
          style={{
            color: '#9CA3AF',
            fontFamily: t.fontFamily.body,
            fontSize: t.fontSize.sm,
            lineHeight: '20px',
            margin: '0 0 24px',
          }}
        >
          Expires in {expiresIn}
        </Text>
      ) : null}
      <Hr style={{ ...rule, margin: '0 0 28px' }} />
    </Section>
  );
}

import { Section, Text } from '@react-email/components';
