export type LifecycleDataRow =
  | { label: string; value: string }
  | { label: string; badge: string; badgeVariant?: LifecycleBadgeVariant };

function rowHasContent(row: LifecycleDataRow): boolean {
  if (!isPresent(row.label)) return false;
  if ('badge' in row) return isPresent(row.badge);
  return isPresent(row.value);
}

export function LifecycleDataCard({ rows }: { rows: LifecycleDataRow[] }) {
  const tokens = getActiveLifecycleTokens();
  const visible = rows.filter(rowHasContent);
  if (visible.length === 0) return null;

  return (
    <Section
      style={{
        border: `1px solid ${tokens.border}`,
        borderRadius: 8,
        marginBottom: 28,
      }}
    >
      {visible.map((row, i) => (
        <Row
          key={row.label}
          style={{
            borderBottom: i < visible.length - 1 ? `1px solid ${tokens.border}` : undefined,
          }}
        >
          <Column style={{ padding: '14px 16px' }}>
            <Text
              style={{
                color: tokens.muted,
                fontFamily: tokens.fontFamily,
                fontSize: 13,
                lineHeight: '20px',
                margin: 0,
              }}
            >
              {row.label}
            </Text>
          </Column>
          <Column align="right" style={{ padding: '14px 16px', verticalAlign: 'middle' }}>
            {'badge' in row ? (
              <LifecycleStatusBadge variant={row.badgeVariant ?? 'success'}>
                {row.badge}
              </LifecycleStatusBadge>
            ) : (
              <Text
                style={{
                  color: tokens.ink,
                  fontFamily: tokens.fontFamily,
                  fontSize: 13,
                  lineHeight: '20px',
                  margin: 0,
                }}
              >
                {row.value}
              </Text>
            )}
          </Column>
        </Row>
      ))}
    </Section>
  );
}

import { Hr, Link, Text } from '@react-email/components';
import type { EmailBrandProps } from '../email-brand';
import { isPresent } from './present';
import { getActiveLifecycleTokens } from './token-context';

export function LifecycleFooter({
  brand,
  recipientEmail,
}: {
  brand: EmailBrandProps;
  recipientEmail?: string;
}) {
  const tokens = getActiveLifecycleTokens();
  const link = { color: tokens.body, textDecoration: 'none' as const };

  const footerLinks = [
    isPresent(brand.unsubscribeUrl)
      ? { label: 'Email preferences', href: brand.unsubscribeUrl }
      : null,
    isPresent(brand.termsUrl) ? { label: 'Terms', href: brand.termsUrl } : null,
    isPresent(brand.privacyUrl) ? { label: 'Privacy', href: brand.privacyUrl } : null,
  ].filter((item): item is { label: string; href: string } => item !== null);

  const companyParts = [brand.legalName, brand.companyAddress].filter(isPresent);
  const hasRecipient = isPresent(recipientEmail);
  const hasMetaLine = hasRecipient || footerLinks.length > 0;
  const hasCompanyLine = companyParts.length > 0;

  if (!hasMetaLine && !hasCompanyLine) return null;

  return (
    <>
      <Hr style={{ borderColor: tokens.border, margin: '0 0 24px' }} />
      {hasMetaLine ? (
        <Text
          style={{
            color: tokens.mutedSoft,
            fontFamily: tokens.fontFamily,
            fontSize: 12,
            lineHeight: 1.6,
            margin: hasCompanyLine ? '0 0 8px' : 0,
          }}
        >
          {hasRecipient ? (
            <>
              Sent to <span style={{ color: tokens.body }}>{recipientEmail}</span>
            </>
          ) : null}
          {footerLinks.map((item, i) => (
            <span key={item.label}>
              {hasRecipient || i > 0 ? ' · ' : null}
              <Link href={item.href} style={link}>
                {item.label}
              </Link>
            </span>
          ))}
        </Text>
      ) : null}
      {hasCompanyLine ? (
        <Text
          style={{
            color: tokens.mutedSoft,
            fontFamily: tokens.fontFamily,
            fontSize: 12,
            margin: 0,
          }}
        >
          {companyParts.join(' · ')}
        </Text>
      ) : null}
    </>
  );
}

