import { Body, Container, Head, Html, Preview } from '@react-email/components';
import type { EmailBrandProps } from '../email-brand';
import type { PartialLifecycleTokens } from '../../tokens.config';
import type { ReactNode } from 'react';
import { LifecycleFooter } from './footer';
import { LifecycleHeader } from './header';
import { resolveLifecycleTokens, setActiveLifecycleTokens } from './token-context';

export interface LifecycleLayoutProps {
  brand: EmailBrandProps;
  preview: string;
  recipientEmail?: string;
  tokens?: PartialLifecycleTokens;
  children: ReactNode;
}

export function LifecycleLayout({
  brand,
  preview,
  recipientEmail,
  tokens,
  children,
}: LifecycleLayoutProps) {
  const resolved = resolveLifecycleTokens(tokens);
  setActiveLifecycleTokens(resolved);

  return (
    <Html lang="en">
      <Head>
        <style>{`html, body { height: 100%; margin: 0; }`}</style>
      </Head>
      <Preview>{preview}</Preview>
      <Body
        style={{
          backgroundColor: resolved.page,
          color: resolved.ink,
          fontFamily: resolved.fontFamily,
          margin: 0,
          minHeight: '100%',
          padding: '32px 16px',
        }}
      >
        <Container
          style={{
            backgroundColor: resolved.card,
            border: `1px solid ${resolved.border}`,
            borderRadius: 8,
            margin: '0 auto',
            maxWidth: 560,
            padding: '48px 48px 32px',
          }}
        >
          <LifecycleHeader brand={brand} />
          {children}
          <LifecycleFooter brand={brand} recipientEmail={recipientEmail} />
        </Container>
      </Body>
    </Html>
  );
}

import { Text } from '@react-email/components';
import type { ReactNode } from 'react';
import { getActiveLifecycleTokens } from './token-context';

export function LifecycleLede({ children }: { children: ReactNode }) {
  const tokens = getActiveLifecycleTokens();

  return (
    <Text
      style={{
        color: tokens.body,
        fontFamily: tokens.fontFamily,
        fontSize: 15,
        lineHeight: '24px',
        margin: '0 0 28px',
      }}
    >
      {children}
    </Text>
  );
}

import { Section, Text } from '@react-email/components';
import { isPresent } from './present';
import { getActiveLifecycleTokens } from './token-context';

export function LifecycleList({
  items,
  ordered = false,
}: {
  items: string[];
  ordered?: boolean;
}) {
  const tokens = getActiveLifecycleTokens();
  const visible = items.filter(isPresent);
  if (visible.length === 0) return null;

  return (
    <Section style={{ marginBottom: 28 }}>
      {visible.map((item, i) => (
        <Text
          key={item}
          style={{
            color: tokens.body,
            fontFamily: tokens.fontFamily,
            fontSize: 14,
            lineHeight: 1.6,
            margin: i < visible.length - 1 ? '0 0 8px' : 0,
          }}
        >
          <span style={{ color: tokens.accent, fontWeight: 500 }}>
            {ordered ? `${i + 1}.` : '✓'}
          </span>{' '}
          {item}
        </Text>
      ))}
    </Section>
  );
}

/** True when a string prop has non-whitespace content. */
export function isPresent(value: unknown): value is string {
  return typeof value === 'string' && value.trim().length > 0;
}

import { Text } from '@react-email/components';
import type { ReactNode } from 'react';
import { isPresent } from './present';
import { getActiveLifecycleTokens } from './token-context';

export function LifecycleQuote({ children }: { children: ReactNode }) {
  const tokens = getActiveLifecycleTokens();

  if (typeof children === 'string' && !isPresent(children)) return null;

  return (
    <Text
      style={{
        borderLeft: `3px solid ${tokens.border}`,
        color: tokens.body,
        fontFamily: tokens.fontFamily,
        fontSize: 14,
        fontStyle: 'italic',
        lineHeight: 1.6,
        margin: '0 0 28px',
        paddingLeft: 16,
      }}
    >
      &ldquo;{children}&rdquo;
    </Text>
  );
}

import { Link, Text } from '@react-email/components';
import { isPresent } from './present';
import { getActiveLifecycleTokens } from './token-context';

export function LifecycleSecurityNote({
  secureAccountUrl,
  supportUrl,
}: {
  secureAccountUrl?: string;
  supportUrl?: string;
}) {
  const tokens = getActiveLifecycleTokens();
  const linkStyle = {
    color: tokens.accent,
    fontWeight: 500,
    textDecoration: 'none' as const,
  };

  const hasSecure = isPresent(secureAccountUrl);
  const hasSupport = isPresent(supportUrl);
  if (!hasSecure && !hasSupport) return null;

  return (
    <Text
      style={{
        color: tokens.muted,
        fontFamily: tokens.fontFamily,
        fontSize: 13,
        lineHeight: 1.6,
        margin: '0 0 32px',
      }}
    >
      If you didn&apos;t make this change,{' '}
      {hasSecure ? (
        <Link href={secureAccountUrl} style={linkStyle}>
          secure your account
        </Link>
      ) : null}
      {hasSecure && hasSupport ? ' or ' : null}
      {hasSupport ? (
        <Link href={supportUrl} style={linkStyle}>
          contact support
        </Link>
      ) : null}
      .
    </Text>
  );
}

import { Text } from '@react-email/components';
import { badgeStylesFor, type LifecycleBadgeVariant, getActiveLifecycleTokens } from './token-context';

export function LifecycleStatusBadge({
  children,
  variant = 'success',
}: {
  children: string;
  variant?: LifecycleBadgeVariant;
}) {
  const tokens = getActiveLifecycleTokens();
  const s = badgeStylesFor(tokens, variant);

  return (
    <span
      style={{
        backgroundColor: s.bg,
        borderRadius: 999,
        color: s.text,
        display: 'inline-block',
        fontFamily: tokens.fontFamily,
        fontSize: 12,
        fontWeight: 500,
        lineHeight: '18px',
        padding: '3px 10px 3px 8px',
      }}
    >
      <span
        style={{
          backgroundColor: s.dot,
          borderRadius: 999,
          display: 'inline-block',
          height: 6,
          marginRight: 6,
          verticalAlign: 'middle',
          width: 6,
        }}
      />
      {children}
    </span>
  );
}

import type { ReactNode } from 'react';
import { getActiveLifecycleTokens } from './token-context';

export function LifecycleStrong({ children }: { children: ReactNode }) {
  const tokens = getActiveLifecycleTokens();

  return <span style={{ color: tokens.ink, fontWeight: 500 }}>{children}</span>;
}

import { Heading } from '@react-email/components';
import { getActiveLifecycleTokens } from './token-context';

export function LifecycleTitle({ children }: { children: string }) {
  const tokens = getActiveLifecycleTokens();

  return (
    <Heading
      style={{
        color: tokens.ink,
        fontFamily: tokens.fontFamily,
        fontSize: 22,
        fontWeight: 600,
        letterSpacing: '-0.02em',
        lineHeight: '28px',
        margin: '0 0 16px',
      }}
    >
      {children}
    </Heading>
  );
}

import {
  mergeLifecycleTokens,
  senseiTokens,
  type LifecycleTokens,
  type PartialLifecycleTokens,
} from '../../tokens.config';

let activeTokens: LifecycleTokens = senseiTokens;

/** Set palette for the current email render (called by LifecycleLayout). */
export function setActiveLifecycleTokens(tokens: LifecycleTokens): void {
  activeTokens = tokens;
}

export function getActiveLifecycleTokens(): LifecycleTokens {
  return activeTokens;
}

export function resolveLifecycleTokens(override?: PartialLifecycleTokens): LifecycleTokens {
  return mergeLifecycleTokens(senseiTokens, override);
}

export type LifecycleBadgeVariant = 'success' | 'warning' | 'danger' | 'neutral';

export function badgeStylesFor(
  tokens: LifecycleTokens,
  variant: LifecycleBadgeVariant,
): { bg: string; text: string; dot: string } {
  switch (variant) {
    case 'success':
      return { bg: tokens.successBg, text: tokens.successText, dot: tokens.successDot };
    case 'warning':
      return { bg: tokens.warningBg, text: tokens.warningText, dot: tokens.warningDot };
    case 'danger':
      return { bg: tokens.dangerBg, text: tokens.dangerText, dot: tokens.dangerDot };
    default:
      return { bg: tokens.neutralBadgeBg, text: tokens.body, dot: tokens.mutedSoft };
  }
}

import { senseiTokens } from '../../tokens.config';

/** @deprecated Use senseiTokens from tokens.config.ts or getActiveLifecycleTokens(). */
export const atlasColors = {
  bg: senseiTokens.card,
  page: senseiTokens.page,
  ink: senseiTokens.ink,
  body: senseiTokens.body,
  muted: senseiTokens.muted,
  mutedSoft: senseiTokens.mutedSoft,
  border: senseiTokens.border,
  accent: senseiTokens.accent,
  successDot: senseiTokens.successDot,
  successBg: senseiTokens.successBg,
  successText: senseiTokens.successText,
  warningDot: senseiTokens.warningDot,
  warningBg: senseiTokens.warningBg,
  warningText: senseiTokens.warningText,
  dangerDot: senseiTokens.dangerDot,
  dangerBg: senseiTokens.dangerBg,
  dangerText: senseiTokens.dangerText,
} as const;

export const atlasFont = senseiTokens.fontFamily;

export type AtlasBadgeVariant = 'success' | 'warning' | 'danger' | 'neutral';

export const atlasBadgeStyles = {
  success: {
    bg: senseiTokens.successBg,
    text: senseiTokens.successText,
    dot: senseiTokens.successDot,
  },
  warning: {
    bg: senseiTokens.warningBg,
    text: senseiTokens.warningText,
    dot: senseiTokens.warningDot,
  },
  danger: {
    bg: senseiTokens.dangerBg,
    text: senseiTokens.dangerText,
    dot: senseiTokens.dangerDot,
  },
  neutral: { bg: senseiTokens.neutralBadgeBg, text: senseiTokens.body, dot: senseiTokens.mutedSoft },
} as const;

import { Column, Row, Section, Text } from '@react-email/components';
import { isPresent } from './present';
import { getActiveLifecycleTokens } from './token-context';

export type LifecycleTotalRow = {
  label: string;
  value: string;
  emphasis?: boolean;
};

export function LifecycleTotals({ rows }: { rows: LifecycleTotalRow[] }) {
  const tokens = getActiveLifecycleTokens();
  const visible = rows.filter((row) => isPresent(row.label) && isPresent(row.value));
  if (visible.length === 0) return null;

  return (
    <Section
      style={{
        border: `1px solid ${tokens.border}`,
        borderRadius: 8,
        marginBottom: 28,
      }}
    >
      {visible.map((row, i) => (
        <Row
          key={row.label}
          style={{
            borderBottom: i < visible.length - 1 ? `1px solid ${tokens.border}` : undefined,
          }}
        >
          <Column style={{ padding: '14px 16px' }}>
            <Text
              style={{
                color: tokens.muted,
                fontFamily: tokens.fontFamily,
                fontSize: 13,
                lineHeight: '20px',
                margin: 0,
              }}
            >
              {row.label}
            </Text>
          </Column>
          <Column align="right" style={{ padding: '14px 16px', verticalAlign: 'middle' }}>
            <Text
              style={{
                color: row.emphasis ? tokens.ink : tokens.body,
                fontFamily: tokens.fontFamily,
                fontSize: row.emphasis ? 18 : 13,
                fontWeight: row.emphasis ? 600 : 400,
                lineHeight: row.emphasis ? '24px' : '20px',
                margin: 0,
              }}
            >
              {row.value}
            </Text>
          </Column>
        </Row>
      ))}
    </Section>
  );
}

import { Section, Text } from '@react-email/components';
import type { ThemeTokens } from '@letterkit/theme';
import { EmailHeading } from './heading';

export interface LineItem {
  name: string;
  detail?: string;
  amount: string;
}

export interface EmailLineItemsProps {
