import { Link, Text } from '@react-email/components';
import type { ThemeTokens } from '@letterkit/theme';

export interface EmailLinkFallbackProps {
  tokens: ThemeTokens;
  url: string;
  label?: string;
}

/**
 * Plain-text URL fallback for clients that strip buttons.
 */
